import type { CashVoucherDto, JournalEntryDto } from '../services/kt/models';

/** Map journal entry list DTO → shape for `VoucherSearchSlideout`. */
export function journalEntryToSearchRow(d: JournalEntryDto): CashVoucherDto {
  const amount = d.lines.reduce((s, l) => s + (Number(l.amount) || 0), 0);
  return {
    id: d.id,
    code: d.code,
    voucherDate: d.entryDate,
    voucherType: d.entryKind ?? '',
    receiptKind: '',
    customerName: '',
    accountCode: '',
    amount,
    exchangeRate: 1,
    status: d.status,
    processingLevel: d.processingLevel ?? '',
    lines: [],
    createdAt: d.createdAt,
  };
}
